#!/usr/bin/env node
// AUTO-GENERATED by ShipIt — do not edit by hand.
//
// Writes a new version into the project's version source using the SAME logic as
// ShipIt's release-version.ts (`writeVersionToSource`). The release workflow
// scaffolded alongside this file invokes it from the `sync-default-branch` job to
// forward-port the released version onto the repo's default (development) branch —
// the release bump itself lands only on the maintenance branch, so without this
// the default branch's version source drifts behind every release. Keep this in
// lockstep with release-version.ts — the templates-release.test.ts consistency
// test fails the build if they drift.
//
// Usage:  node shipit-write-version.mjs <package.json|Cargo.toml|pyproject.toml|VERSION> <newVersion> [path]
// Rewrites the version field in place (preserving formatting), bumps an adjacent
// package-lock.json best-effort for Node, and exits non-zero with a diagnostic on
// stderr when the version field can't be located.

import fs from "node:fs";
import path from "node:path";

// Detect the indentation unit a JSON file uses so a rewrite preserves formatting.
function detectJsonIndent(raw) {
  const m = /\n([ \t]+)\S/.exec(raw);
  return m && m[1] ? m[1] : "  ";
}

function rewritePackageJson(raw, newVersion) {
  const parsed = JSON.parse(raw);
  parsed.version = newVersion;
  const indent = detectJsonIndent(raw);
  const out = JSON.stringify(parsed, null, indent);
  return raw.endsWith("\n") ? out + "\n" : out;
}

function rewriteTomlVersion(raw, sectionRes, newVersion) {
  for (const sectionRe of sectionRes) {
    const section = sectionRe.exec(raw);
    if (!section) continue;
    const body = section[1] || "";
    const versionRe = /^(\s*version\s*=\s*")([^"]+)(")/m;
    if (!versionRe.test(body)) continue;
    const newBody = body.replace(versionRe, "$1" + newVersion + "$3");
    return raw.slice(0, section.index) + raw.slice(section.index).replace(body, newBody);
  }
  return null;
}

// Best-effort root-version bump of a Node lockfile next to the package.json. npm
// records the version at the lockfile root AND under packages[""]; leaving them
// stale makes `npm ci` warn. String-level edit only — no package manager run.
function bumpNodeLockfile(pkgPath, newVersion) {
  const lockPath = path.join(path.dirname(pkgPath), "package-lock.json");
  let raw;
  try {
    raw = fs.readFileSync(lockPath, "utf8");
  } catch {
    return; // no lockfile — nothing to bump
  }
  try {
    const parsed = JSON.parse(raw);
    if (typeof parsed.version === "string") parsed.version = newVersion;
    const rootPkg = parsed.packages && parsed.packages[""];
    if (rootPkg && typeof rootPkg.version === "string") rootPkg.version = newVersion;
    const indent = detectJsonIndent(raw);
    const out = JSON.stringify(parsed, null, indent);
    fs.writeFileSync(lockPath, raw.endsWith("\n") ? out + "\n" : out, "utf8");
  } catch {
    // Malformed lockfile — leave it untouched rather than risk corrupting it.
  }
}

const source = process.argv[2];
const newVersion = process.argv[3];
if (!newVersion) {
  process.stderr.write("Usage: shipit-write-version.mjs <source> <newVersion> [path]\n");
  process.exit(2);
}

const KNOWN = ["package.json", "Cargo.toml", "pyproject.toml", "VERSION"];
if (!KNOWN.includes(source)) {
  process.stderr.write("Unknown version source: " + String(source) + "\n");
  process.stderr.write("Expected one of: " + KNOWN.join(", ") + "\n");
  process.exit(2);
}

// Default to the conventional filename in the repo root; an explicit path
// (monorepo version source) overrides it.
const file = process.argv[4] || source;

let raw;
try {
  raw = fs.readFileSync(file, "utf8");
} catch {
  process.stderr.write("Could not read " + file + "\n");
  process.exit(1);
}

let next = null;
switch (source) {
  case "package.json":
    next = rewritePackageJson(raw, newVersion);
    break;
  case "Cargo.toml":
    next = rewriteTomlVersion(raw, [/\[package\]([\s\S]*?)(?=\n\[|\s*$)/], newVersion);
    break;
  case "pyproject.toml":
    next = rewriteTomlVersion(
      raw,
      [/\[project\]([\s\S]*?)(?=\n\[|\s*$)/, /\[tool\.poetry\]([\s\S]*?)(?=\n\[|\s*$)/],
      newVersion,
    );
    break;
  case "VERSION": {
    const lines = raw.split("\n");
    lines[0] = newVersion;
    next = lines.join("\n");
    break;
  }
}

if (next === null) {
  process.stderr.write("Could not locate the version field in " + file + " to rewrite.\n");
  process.exit(1);
}
fs.writeFileSync(file, next, "utf8");
if (source === "package.json") bumpNodeLockfile(file, newVersion);
